// ── EDIT THIS MAP: one entry per store ──────────────────────────────
// Key by location_name (what staff see) or location_id (UUID from wOrder).
const accounts = {
  "Woso Emporia":   { username: "REPLACE_USER_1", password: "REPLACE_PASS_1" },
  "Another Store":  { username: "REPLACE_USER_2", password: "REPLACE_PASS_2" },
};
// ────────────────────────────────────────────────────────────────────
const body = $('Webhook').first().json.body || {};
const acc = accounts[body.location_id] || accounts[body.location_name];
if (!acc) throw new Error('No Tingstad account configured for location: ' + (body.location_name || body.location_id));
return [{ json: { username: acc.username, password: acc.password } }];

const cookiesFrom = (node) => {
  const sc = $(node).first().json.headers?.['set-cookie'] || [];
  return (Array.isArray(sc) ? sc : [sc]).map(c => String(c).split(';')[0]);
};
const pairs = [...cookiesFrom('Get Login Page'), ...cookiesFrom('Login')];
const byName = {};
for (const p of pairs) { const name = p.split('=')[0]; if (name) byName[name] = p; }
const cookie = Object.values(byName).join('; ');
const products = $('Webhook').first().json.body.products || [];
return products.map(p => ({ json: {
  productNumber: String(p.tingstad_id),
  amount: p.quantity,
  cookie,
} }));

const items = $input.all();
const total = items.length;
const failed = items.filter(i => (i.json.statusCode || 200) >= 400).length;
return [{ json: { ok: failed === 0, count: total, added: total - failed, failed } }];
